import { useEffect, useState } from "react"

const PROGRESS_MESSAGES: [number, string][] = [
  [0,  "Thinking..."],
  [8,  "Still working..."],
  [20, "This is taking a bit longer than usual..."],
  [40, "Almost there — complex question."],
]

function useThinkingProgress(isLoading: boolean): string {
  const [elapsed, setElapsed] = useState(0)
  const [msg, setMsg] = useState(PROGRESS_MESSAGES[0][1])

  useEffect(() => {
    if (!isLoading) { setElapsed(0); setMsg(PROGRESS_MESSAGES[0][1]); return }
    const interval = setInterval(() => {
      setElapsed(prev => {
        const next = prev + 1
        const latest = [...PROGRESS_MESSAGES].reverse().find(([t]) => next >= t)
        if (latest) setMsg(latest[1])
        return next
      })
    }, 1000)
    return () => clearInterval(interval)
  }, [isLoading])

  return msg
}

function LoadingIndicator({ isLoading }: { isLoading: boolean }) {
  const message = useThinkingProgress(isLoading)
  if (!isLoading) return null
  return (
    <div className="loading-indicator" role="status" aria-live="polite">
      <span className="spinner" aria-hidden="true" />
      <span>{message}</span>
    </div>
  )
}

from enum import Enum
from dataclasses import dataclass

class TimeoutPhase(Enum):
    CONNECT = "connect"
    FIRST_TOKEN = "first_token"
    READ_STALL = "read_stall"
    TOTAL = "total"

@dataclass
class TimeoutResult:
    success: bool
    text: str | None
    phase: TimeoutPhase | None
    attempts: int


async def resilient_call(
    messages: list[dict],
    max_tokens: int = 512,
    max_attempts: int = 2,
) -> TimeoutResult:
    for attempt in range(1, max_attempts + 1):
        try:
            timeout = adaptive_timeout(max_tokens)
            async with asyncio.timeout(timeout):
                resp = await client.chat.completions.create(
                    model="gpt-4o",
                    messages=messages,
                    max_tokens=max_tokens,
                )
            return TimeoutResult(
                success=True,
                text=resp.choices[0].message.content,
                phase=None,
                attempts=attempt,
            )
        except asyncio.TimeoutError:
            if attempt < max_attempts:
                # On second attempt, halve the budget and ask for a shorter answer
                max_tokens = max_tokens // 2
                messages = messages + [{
                    "role": "system",
                    "content": "Previous response timed out. Please give a shorter answer.",
                }]
                await asyncio.sleep(2 ** attempt)  # brief backoff
            else:
                return TimeoutResult(
                    success=False,
                    text=None,
                    phase=TimeoutPhase.TOTAL,
                    attempts=attempt,
                )
    # Should not reach here
    return TimeoutResult(success=False, text=None, phase=None, attempts=max_attempts)
